INSERT INTO num_systems (id, name, is_app_default, reference_only, value_range, note, letter_values, value_to_letters, extra) VALUES ('pythagorean', 'Pythagorean', TRUE, FALSE, '1-9', 'Sequential 1-9 cycle through the alphabet. This map is identical to lib/numerology.js LETTER_VALUES.', '{"a": 1, "b": 2, "c": 3, "d": 4, "e": 5, "f": 6, "g": 7, "h": 8, "i": 9, "j": 1, "k": 2, "l": 3, "m": 4, "n": 5, "o": 6, "p": 7, "q": 8, "r": 9, "s": 1, "t": 2, "u": 3, "v": 4, "w": 5, "x": 6, "y": 7, "z": 8}'::JSONB, '{"1": ["a", "j", "s"], "2": ["b", "k", "t"], "3": ["c", "l", "u"], "4": ["d", "m", "v"], "5": ["e", "n", "w"], "6": ["f", "o", "x"], "7": ["g", "p", "y"], "8": ["h", "q", "z"], "9": ["i", "r"]}'::JSONB, '{}'::JSONB) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, is_app_default = EXCLUDED.is_app_default, reference_only = EXCLUDED.reference_only, value_range = EXCLUDED.value_range, note = EXCLUDED.note, letter_values = EXCLUDED.letter_values, value_to_letters = EXCLUDED.value_to_letters, extra = EXCLUDED.extra;
INSERT INTO num_systems (id, name, is_app_default, reference_only, value_range, note, letter_values, value_to_letters, extra) VALUES ('chaldean', 'Chaldean (Cheiro standard)', FALSE, TRUE, '1-8', 'Classical Chaldean (per Cheiro / Book of Numbers). The number 9 is NEVER assigned to a letter (held as sacred), though a name total can still sum to 9. The most-disputed letters between Chaldean lineages are X (5 vs 6) and Z (7 vs 8); the standard/Cheiro values used here are X=5, Z=7. This table is for an optional alternate system; the app does not compute with it.', '{"a": 1, "i": 1, "j": 1, "q": 1, "y": 1, "b": 2, "k": 2, "r": 2, "c": 3, "g": 3, "l": 3, "s": 3, "d": 4, "m": 4, "t": 4, "e": 5, "h": 5, "n": 5, "x": 5, "u": 6, "v": 6, "w": 6, "o": 7, "z": 7, "f": 8, "p": 8}'::JSONB, '{"1": ["a", "i", "j", "q", "y"], "2": ["b", "k", "r"], "3": ["c", "g", "l", "s"], "4": ["d", "m", "t"], "5": ["e", "h", "n", "x"], "6": ["u", "v", "w"], "7": ["o", "z"], "8": ["f", "p"]}'::JSONB, '{"nine_rule": "No letter maps to 9 in classical Chaldean. 9 is considered sacred and excluded from letter assignment.", "known_variants": "Some ''improved'' Chaldean systems (e.g. astronumero) deliberately assign 9 and shift S/H/T/E values; these are non-classical and not used here."}'::JSONB) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, is_app_default = EXCLUDED.is_app_default, reference_only = EXCLUDED.reference_only, value_range = EXCLUDED.value_range, note = EXCLUDED.note, letter_values = EXCLUDED.letter_values, value_to_letters = EXCLUDED.value_to_letters, extra = EXCLUDED.extra;
