INSERT INTO num_vowel_consonant_rules (id, vowels, y_is_vowel, w_is_vowel, app_convention, standard_phonetic_rule) VALUES ('app_default', ARRAY['a','e','i','o','u']::TEXT[], TRUE, FALSE, '{"name": "Phonetic Y, syllable scope", "base_vowels": ["a", "e", "i", "o", "u"], "y_is_vowel": "conditional", "w_is_vowel": false, "summary": "Y counts as a VOWEL except when it acts as a consonant: (1) immediately preceded by a base vowel (Maya, Murray, Raymond), or (2) word-initial and immediately followed by a base vowel (Yolanda, the soft-J glide). Otherwise Y is a vowel (Lynn, Yvonne, Carolyn, Bryant, Kathryn). W is always a consonant.", "scope": "syllable", "scope_note": "The rule is scoped to the SYLLABLE, not the whole word. This is the universally cited convention: Y is a vowel when it carries the only vowel sound in its own syllable, even if the word has other vowels elsewhere (Carolyn, Kathryn, Brittany, Sydney). Word-scope is a common misimplementation and is NOT used.", "deterministic_algorithm": "For each Y at position i in a name-word: consonant if name[i-1] is a base vowel; consonant if i==0 and name[i+1] is a base vowel; otherwise vowel. This inspects only the Y''s immediate neighbors, which is exactly what makes it syllable-scoped without full syllabification."}'::JSONB, '{"citation": {"rule": "Phonetic Y rule, scoped to the syllable", "sources": ["Hans Decoz, World Numerology - ''Y is a vowel when it is the only vowel sound in the syllable.''", "Matthew Oliver Goodwin, ''Numerology: The Complete Guide'' (1981) - ''Y is a vowel when there is no other vowel in a syllable.''"], "consensus": "High for syllable-scope (the two leading authorities agree). The broader question of whether to count Y at all is school-dependent (Juno Jordan never counts Y); Decoz/Goodwin phonetic Y is the modern majority. W-as-vowel is a fringe minority (Goodwin only); the app keeps W as a consonant.", "research_doc": "numerology_Y_RULE_RESEARCH.md"}, "history": {"before_2026_06_23": "The app previously treated Y and W as always consonants (the Juno Jordan minority convention), so vowel-Y names (Lynn, Carolyn, Yvonne, Bryant) produced different Soul Urge / Personality numbers than Decoz and most popular calculators.", "changed_2026_06_23": "Switched lib/numerology.js to the syllable-scope phonetic Y rule above to match the cited authorities."}}'::JSONB) ON CONFLICT (id) DO UPDATE SET vowels = EXCLUDED.vowels, y_is_vowel = EXCLUDED.y_is_vowel, w_is_vowel = EXCLUDED.w_is_vowel, app_convention = EXCLUDED.app_convention, standard_phonetic_rule = EXCLUDED.standard_phonetic_rule;
INSERT INTO num_reduction_rules (id, app_function, rule, used_for, preserves_masters) VALUES ('reduceToSingle', 'reduceToSingle(n)', 'Repeatedly sum the digits until the result is a single digit (1-9) OR a master number (11, 22, 33). Stop as soon as the running value is 11, 22, or 33.', ARRAY['life_path','expression','soul_urge','personality','maturity','personal_year_final','pinnacles','life_cycle_components']::TEXT[], TRUE) ON CONFLICT (id) DO UPDATE SET app_function = EXCLUDED.app_function, rule = EXCLUDED.rule, used_for = EXCLUDED.used_for, preserves_masters = EXCLUDED.preserves_masters;
INSERT INTO num_reduction_rules (id, app_function, rule, used_for, preserves_masters) VALUES ('reduceStrict', 'reduceStrict(n)', 'Repeatedly sum the digits until the result is a single digit (1-9). Master numbers are NOT preserved here.', ARRAY['pinnacle_and_challenge_month_day_year_components','challenge_results','personal_year_components']::TEXT[], FALSE) ON CONFLICT (id) DO UPDATE SET app_function = EXCLUDED.app_function, rule = EXCLUDED.rule, used_for = EXCLUDED.used_for, preserves_masters = EXCLUDED.preserves_masters;
INSERT INTO num_core_numbers (id, name, alternate_names, inputs, formula, app_implementation, reduction_mode, can_carry_karmic_debt, meaning_context, note) VALUES ('life_path', 'Life Path', '{}'::TEXT[], ARRAY['birthdate']::TEXT[], 'Reduce the birth month, birth day, and the digit-sum of the birth year each to a single digit (preserving masters), sum those three, then reduce the total (preserving masters).', 'm = reduceToSingle(month); d = reduceToSingle(day); y = reduceToSingle(digitSum(year)); result = reduceToSingle(m + d + y).', 'reduceToSingle', TRUE, 'life_path', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, alternate_names = EXCLUDED.alternate_names, inputs = EXCLUDED.inputs, formula = EXCLUDED.formula, app_implementation = EXCLUDED.app_implementation, reduction_mode = EXCLUDED.reduction_mode, can_carry_karmic_debt = EXCLUDED.can_carry_karmic_debt, meaning_context = EXCLUDED.meaning_context, note = EXCLUDED.note;
INSERT INTO num_core_numbers (id, name, alternate_names, inputs, formula, app_implementation, reduction_mode, can_carry_karmic_debt, meaning_context, note) VALUES ('expression', 'Expression', ARRAY['Destiny']::TEXT[], ARRAY['full_birth_name']::TEXT[], 'For each name part, sum the Pythagorean values of all its letters and reduce that part (preserving masters); sum the reduced parts and reduce the total (preserving masters).', 'For each whitespace-split name: nameSum = sum(letterValue(ch)); add reduceToSingle(nameSum). Then result = reduceToSingle(totalOfReducedParts).', 'reduceToSingle', TRUE, 'expression', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, alternate_names = EXCLUDED.alternate_names, inputs = EXCLUDED.inputs, formula = EXCLUDED.formula, app_implementation = EXCLUDED.app_implementation, reduction_mode = EXCLUDED.reduction_mode, can_carry_karmic_debt = EXCLUDED.can_carry_karmic_debt, meaning_context = EXCLUDED.meaning_context, note = EXCLUDED.note;
INSERT INTO num_core_numbers (id, name, alternate_names, inputs, formula, app_implementation, reduction_mode, can_carry_karmic_debt, meaning_context, note) VALUES ('soul_urge', 'Soul Urge', ARRAY['Heart''s Desire']::TEXT[], ARRAY['full_birth_name']::TEXT[], 'Same as Expression but using VOWELS only (per the app''s vowel set a,e,i,o,u; Y excluded).', 'For each name: vowelSum = sum of letterValue(ch) where ch is in {a,e,i,o,u}; add reduceToSingle(vowelSum). result = reduceToSingle(total).', 'reduceToSingle', TRUE, 'soul_urge', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, alternate_names = EXCLUDED.alternate_names, inputs = EXCLUDED.inputs, formula = EXCLUDED.formula, app_implementation = EXCLUDED.app_implementation, reduction_mode = EXCLUDED.reduction_mode, can_carry_karmic_debt = EXCLUDED.can_carry_karmic_debt, meaning_context = EXCLUDED.meaning_context, note = EXCLUDED.note;
INSERT INTO num_core_numbers (id, name, alternate_names, inputs, formula, app_implementation, reduction_mode, can_carry_karmic_debt, meaning_context, note) VALUES ('personality', 'Personality', '{}'::TEXT[], ARRAY['full_birth_name']::TEXT[], 'Same as Expression but using CONSONANTS only (every letter with a Pythagorean value that is NOT in the app vowel set; Y and W count as consonants).', 'For each name: conSum = sum of letterValue(ch) where ch is NOT in {a,e,i,o,u} and has a value; add reduceToSingle(conSum). result = reduceToSingle(total).', 'reduceToSingle', TRUE, 'personality', NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, alternate_names = EXCLUDED.alternate_names, inputs = EXCLUDED.inputs, formula = EXCLUDED.formula, app_implementation = EXCLUDED.app_implementation, reduction_mode = EXCLUDED.reduction_mode, can_carry_karmic_debt = EXCLUDED.can_carry_karmic_debt, meaning_context = EXCLUDED.meaning_context, note = EXCLUDED.note;
INSERT INTO num_core_numbers (id, name, alternate_names, inputs, formula, app_implementation, reduction_mode, can_carry_karmic_debt, meaning_context, note) VALUES ('birthday', 'Birthday Number', ARRAY['Day of Birth']::TEXT[], ARRAY['birthdate']::TEXT[], 'The day of the month of birth, as-is, NOT reduced. Range 1-31.', 'Number(birthdate.split(''-'')[2]).', 'none', TRUE, 'birthday', 'The app keeps the raw 1-31 day and looks up a per-day meaning (see meaning_tables.birthday). Some practitioners also reduce it to a single digit; the app does not.') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, alternate_names = EXCLUDED.alternate_names, inputs = EXCLUDED.inputs, formula = EXCLUDED.formula, app_implementation = EXCLUDED.app_implementation, reduction_mode = EXCLUDED.reduction_mode, can_carry_karmic_debt = EXCLUDED.can_carry_karmic_debt, meaning_context = EXCLUDED.meaning_context, note = EXCLUDED.note;
INSERT INTO num_core_numbers (id, name, alternate_names, inputs, formula, app_implementation, reduction_mode, can_carry_karmic_debt, meaning_context, note) VALUES ('maturity', 'Maturity Number', ARRAY['Realization','Power Number']::TEXT[], ARRAY['life_path','expression']::TEXT[], 'Reduce (Life Path + Expression), preserving masters.', 'reduceToSingle(lifePath + expression).', 'reduceToSingle', FALSE, 'maturity', 'Represents the dominant theme that emerges in later life, roughly age 35 onward.') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, alternate_names = EXCLUDED.alternate_names, inputs = EXCLUDED.inputs, formula = EXCLUDED.formula, app_implementation = EXCLUDED.app_implementation, reduction_mode = EXCLUDED.reduction_mode, can_carry_karmic_debt = EXCLUDED.can_carry_karmic_debt, meaning_context = EXCLUDED.meaning_context, note = EXCLUDED.note;
INSERT INTO num_personal_cycles (id, name, added_by_research, inputs, formula, app_implementation, example, output_range, reduction_mode, meaning_context, note) VALUES ('personal_year', 'Personal Year', FALSE, ARRAY['birth_month','birth_day','current_calendar_year']::TEXT[], 'Reduce (reduced birth month + reduced birth day + reduced current year) to a single digit.', 'sum = reduceStrict(month) + reduceStrict(day) + reduceStrict(digitSum(currentYear)); result = reduceToSingle(sum). The app reduces the final result with master preservation but in practice Personal Year is presented 1-9.', NULL, '1-9', 'reduceToSingle (app), components via reduceStrict', 'personal_year', 'Some schools keep 11/22 if the Personal Year total is a master number. The app reduces to 1-9. Documented; app behavior preserved.') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, added_by_research = EXCLUDED.added_by_research, inputs = EXCLUDED.inputs, formula = EXCLUDED.formula, app_implementation = EXCLUDED.app_implementation, example = EXCLUDED.example, output_range = EXCLUDED.output_range, reduction_mode = EXCLUDED.reduction_mode, meaning_context = EXCLUDED.meaning_context, note = EXCLUDED.note;
INSERT INTO num_personal_cycles (id, name, added_by_research, inputs, formula, app_implementation, example, output_range, reduction_mode, meaning_context, note) VALUES ('personal_month', 'Personal Month', TRUE, ARRAY['personal_year','current_calendar_month']::TEXT[], 'Reduce (Personal Year + current calendar month number) to a single digit.', NULL, 'Personal Year 1 + June (6) = 7.', '1-9', NULL, 'personal_year', 'Not computed by the app yet. Theme reuses the Personal Year meaning table (same 1-9 archetypes at a monthly scale).') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, added_by_research = EXCLUDED.added_by_research, inputs = EXCLUDED.inputs, formula = EXCLUDED.formula, app_implementation = EXCLUDED.app_implementation, example = EXCLUDED.example, output_range = EXCLUDED.output_range, reduction_mode = EXCLUDED.reduction_mode, meaning_context = EXCLUDED.meaning_context, note = EXCLUDED.note;
INSERT INTO num_personal_cycles (id, name, added_by_research, inputs, formula, app_implementation, example, output_range, reduction_mode, meaning_context, note) VALUES ('personal_day', 'Personal Day', TRUE, ARRAY['personal_month','current_calendar_day']::TEXT[], 'Reduce (Personal Month + current calendar day number) to a single digit.', NULL, 'Personal Month 7 + day 23 = 30 -> 3.', '1-9', NULL, 'personal_year', 'Not computed by the app yet. Theme reuses the Personal Year meaning table at a daily scale.') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, added_by_research = EXCLUDED.added_by_research, inputs = EXCLUDED.inputs, formula = EXCLUDED.formula, app_implementation = EXCLUDED.app_implementation, example = EXCLUDED.example, output_range = EXCLUDED.output_range, reduction_mode = EXCLUDED.reduction_mode, meaning_context = EXCLUDED.meaning_context, note = EXCLUDED.note;
INSERT INTO num_pinnacles (id, formulas, component_reduction, master_numbers_preserved, timing, meaning_context) VALUES ('pinnacles', '{"first": "reduceToSingle(reducedMonth + reducedDay)", "second": "reduceToSingle(reducedDay + reducedYear)", "third": "reduceToSingle(first + second)", "fourth": "reduceToSingle(reducedMonth + reducedYear)"}'::JSONB, 'month, day, and year(digit-sum) reduced via reduceStrict before combining (matches app pinnacles()).', TRUE, '{"convention": "36_minus_life_path", "first": "Birth to age (36 - reducedLifePath).", "second": "9 years (ends at 45 - lifePath).", "third": "9 years (ends at 54 - lifePath).", "fourth": "From (54 - lifePath) to end of life.", "app_implementation": "firstEnd = 36 - lifePath; windows: Birth..firstEnd, firstEnd+1..firstEnd+9, firstEnd+10..firstEnd+18, firstEnd+19+. Matches Decoz; firstEnd ranges 27 (LP9) to 35 (LP1).", "alternative_conventions": "affinitynumerology states the first pinnacle ''lasts 27 to 35 years'' as a range; tokenrock says ''between ages 30 and 35''. These are prose roundings of the same 36-LP output, not different math. No mainstream source applies a separate hard cap."}'::JSONB, 'pinnacle') ON CONFLICT (id) DO UPDATE SET formulas = EXCLUDED.formulas, component_reduction = EXCLUDED.component_reduction, master_numbers_preserved = EXCLUDED.master_numbers_preserved, timing = EXCLUDED.timing, meaning_context = EXCLUDED.meaning_context;
INSERT INTO num_challenges (id, formulas, labels, component_reduction, master_numbers_preserved, output_range, timing_note, meaning_context) VALUES ('challenges', '{"first": "abs(reducedMonth - reducedDay)", "second": "abs(reducedDay - reducedYear)", "third_main": "abs(first - second)", "fourth": "abs(reducedMonth - reducedYear)"}'::JSONB, '{"first": "First Challenge", "second": "Second Challenge", "third": "Third (Main) Challenge", "fourth": "Fourth Challenge"}'::JSONB, 'month, day, year(digit-sum) reduced via reduceStrict; results reduced via reduceStrict (matches app challenges()).', FALSE, '0-8', 'Challenges are fluid and overlapping in the canonical system: First felt birth to ~30-35, Second ~35 to ~55/60, Third (Main) active birth to death, Fourth most felt in later life. The app does not assign ages to challenges; it labels them only.', 'challenge') ON CONFLICT (id) DO UPDATE SET formulas = EXCLUDED.formulas, labels = EXCLUDED.labels, component_reduction = EXCLUDED.component_reduction, master_numbers_preserved = EXCLUDED.master_numbers_preserved, output_range = EXCLUDED.output_range, timing_note = EXCLUDED.timing_note, meaning_context = EXCLUDED.meaning_context;
INSERT INTO num_life_cycles (id, formulas, labels, themes, master_numbers_preserved, app_engine_timing, canonical_decoz_timing, meaning_context, meaning_note) VALUES ('life_cycles', '{"first_formative": "reduceToSingle(birthMonth)", "second_productive": "reduceToSingle(birthDay)", "third_harvest": "reduceToSingle(digitSum(birthYear))"}'::JSONB, '{"first": "Formative", "second": "Productive", "third": "Harvest"}'::JSONB, '{"first": "Formative years: shaped by family and environment, finding your nature.", "second": "Productive years: individual talents emerge, working toward self-mastery.", "third": "Harvest years: fullest self-expression and the fruition of who you became."}'::JSONB, TRUE, '{"first": "Birth to age (36 - lifePath).", "second": "Next 27 years (firstEnd+1 to firstEnd+27).", "third": "From (firstEnd+28) to end of life.", "note": "Reproducible: this is what lib/numerology.js lifeCycles() does. It reuses the pinnacle boundary 36-lifePath."}'::JSONB, '{"first": "Birth to the first Personal Year 1 cycle on or after age 27.", "second": "Exactly 27 years.", "third": "To end of life.", "note": "Documented for reference. Decoz does NOT tie Period-Cycle 1 to 36-lifePath; he ties it to the 9-year Personal-Year wheel. The app''s reuse of 36-lifePath is a simplification/conflation. App code intentionally left unchanged."}'::JSONB, 'life_path', 'Period Cycle number meanings reuse the general single-digit / Life Path archetypes (1-9, 11, 22) at the scale of a life phase.') ON CONFLICT (id) DO UPDATE SET formulas = EXCLUDED.formulas, labels = EXCLUDED.labels, themes = EXCLUDED.themes, master_numbers_preserved = EXCLUDED.master_numbers_preserved, app_engine_timing = EXCLUDED.app_engine_timing, canonical_decoz_timing = EXCLUDED.canonical_decoz_timing, meaning_context = EXCLUDED.meaning_context, meaning_note = EXCLUDED.meaning_note;
INSERT INTO num_karmic_debt (number, reduces_to, theme, descriptor) VALUES (13, 4, 'Work and focus', 'Lasting results come from steady, organized effort. The growth here is choosing discipline over shortcuts and finishing what you start.') ON CONFLICT (number) DO UPDATE SET reduces_to = EXCLUDED.reduces_to, theme = EXCLUDED.theme, descriptor = EXCLUDED.descriptor;
INSERT INTO num_karmic_debt (number, reduces_to, theme, descriptor) VALUES (14, 5, 'Freedom and moderation', 'Freedom is the gift and the trap. The growth here is staying adaptable without tipping into excess, impulsiveness, or escape.') ON CONFLICT (number) DO UPDATE SET reduces_to = EXCLUDED.reduces_to, theme = EXCLUDED.theme, descriptor = EXCLUDED.descriptor;
INSERT INTO num_karmic_debt (number, reduces_to, theme, descriptor) VALUES (16, 7, 'Ego and renewal', 'Old versions of the self get stripped away so a truer one can form. The growth here is humility, honesty in love, and rebuilding on solid ground.') ON CONFLICT (number) DO UPDATE SET reduces_to = EXCLUDED.reduces_to, theme = EXCLUDED.theme, descriptor = EXCLUDED.descriptor;
INSERT INTO num_karmic_debt (number, reduces_to, theme, descriptor) VALUES (19, 1, 'Independence and interdependence', 'Strength is real, but going it alone has limits. The growth here is using power with integrity and learning to receive help, not just give it.') ON CONFLICT (number) DO UPDATE SET reduces_to = EXCLUDED.reduces_to, theme = EXCLUDED.theme, descriptor = EXCLUDED.descriptor;
