INSERT INTO num_essence_transit (id, transit_letters, essence, confidence_note) VALUES ('essence_transit', '{"tracks": {"physical": "first name", "mental": "middle name", "spiritual": "last name"}, "rule": "Within each track, each letter is active for a number of years equal to its Pythagorean value, then the next letter takes over. When a name''s letters are exhausted, the track repeats from its first letter.", "example": "In ''Mike'', M (value 4) is active 4 years, then the next letter for its value, and so on; the full name''s letter values sum to its cycle length before repeating."}'::JSONB, '{"rule": "For a given year (birthday to birthday), the Essence equals the sum of the three currently active transit letters (physical + mental + spiritual), then reduced to a single digit (or kept as a master / karmic-debt two-digit total before reducing).", "duration": "An Essence persists until one of the three active transit letters changes, so it can repeat across multiple years.", "karmic_debt": "A pre-reduction Essence sum of 13, 14, 16, or 19 carries the matching karmic debt for that year."}'::JSONB, 'Letter-duration-equals-its-value and the three-track summation are well sourced. Edge cases (names of unequal length, master retention in Essence) are moderately confident and not firsthand-verified end to end.') ON CONFLICT (id) DO UPDATE SET transit_letters = EXCLUDED.transit_letters, essence = EXCLUDED.essence, confidence_note = EXCLUDED.confidence_note;
