INSERT INTO num_meaning_life_path (number, title, description) VALUES ('1', 'The Leader', 'Independent, ambitious, and pioneering. You are here to develop individuality and self-confidence. You lead by example and blaze new trails.') ON CONFLICT (number) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_life_path (number, title, description) VALUES ('2', 'The Diplomat', 'Cooperative, sensitive, and harmonizing. You are here to learn partnership and balance. Your strength lies in mediation and bringing people together.') ON CONFLICT (number) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_life_path (number, title, description) VALUES ('3', 'The Communicator', 'Creative, expressive, and joyful. You are here to inspire through words, art, and social connection. Your optimism uplifts those around you.') ON CONFLICT (number) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_life_path (number, title, description) VALUES ('4', 'The Builder', 'Practical, disciplined, and dependable. You are here to create lasting foundations. You find fulfillment through hard work and systematic effort.') ON CONFLICT (number) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_life_path (number, title, description) VALUES ('5', 'The Freedom Seeker', 'Adventurous, versatile, and dynamic. You are here to experience life fully through change and variety. You thrive on exploration and sensory experience.') ON CONFLICT (number) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_life_path (number, title, description) VALUES ('6', 'The Nurturer', 'Responsible, loving, and protective. You are here to serve family and community. Your home is your sanctuary and your heart holds deep compassion.') ON CONFLICT (number) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_life_path (number, title, description) VALUES ('7', 'The Seeker', 'Analytical, introspective, and spiritual. You are here to pursue knowledge and inner truth. Solitude fuels your deep understanding of life''s mysteries.') ON CONFLICT (number) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_life_path (number, title, description) VALUES ('8', 'The Powerhouse', 'Ambitious, authoritative, and materially focused. You are here to master the material world: wealth, status, and achievement. Balance power with integrity.') ON CONFLICT (number) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_life_path (number, title, description) VALUES ('9', 'The Humanitarian', 'Compassionate, idealistic, and selfless. You are here to serve the greater good and let go of the personal. Your path is one of wisdom through experience.') ON CONFLICT (number) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_life_path (number, title, description) VALUES ('11', 'The Intuitive (Master)', 'Highly intuitive, inspirational, and spiritually aware. You carry the vibration of 2 amplified, a channel between the conscious and unconscious.') ON CONFLICT (number) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_life_path (number, title, description) VALUES ('22', 'The Master Builder', 'Visionary, practical idealist, and powerful manifestor. You carry the vibration of 4 amplified, capable of turning the grandest dreams into reality.') ON CONFLICT (number) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_life_path (number, title, description) VALUES ('33', 'The Master Teacher', 'Selfless, nurturing at the highest level, and spiritually devoted. You carry the vibration of 6 amplified, a healer and teacher of unconditional love.') ON CONFLICT (number) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (1, 'The Leader', 'A self-starting innovator with strong drive and independence, comfortable going first.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (2, 'The Peacemaker', 'Warm, intuitive, and cooperative, with a gift for finding fair solutions and creating harmony.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (3, 'The Creative', 'A natural communicator with real artistic flair and an expressive, charismatic presence.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (4, 'The Rock', 'Grounded, disciplined, and dependable, you bring stability and follow-through to everything.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (5, 'The Freedom Lover', 'Highly adaptable and quick on your feet, you thrive on variety and seize fleeting opportunities.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (6, 'The Nurturer', 'A natural caregiver with a talent for supporting, healing, and protecting the people you love.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (7, 'The Seeker', 'A sharp, reflective mind drawn to deeper truths, research, and quiet understanding.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (8, 'The Achiever', 'Goal-oriented and capable, with a strong instinct for business, judgment, and results.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (9, 'The Humanitarian', 'Compassionate and service-minded, you shine when speaking up for and helping others.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (10, 'The Director', 'A sharp leader who can dream up ideas, organize the details, and direct others to execute.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (11, 'The Intuitive', 'Keenly perceptive, you read unspoken feelings and make a natural counselor or guide.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (12, 'The Self-Expressive', 'Rich imagination and creativity surface in everything you take seriously.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
