INSERT INTO num_meaning_birthday (day, title, description) VALUES (15, 'The Caregiver', 'Your love for others runs wide and deep, paired with a curious, social streak.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
