INSERT INTO num_meaning_birthday (day, title, description) VALUES (17, 'The Self-Reliant', 'Independent and ambitious, you do remarkable work when you run things your own way.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (18, 'The Worldly Giver', 'Broad-minded and open-hearted, you want to leave the world better and feel best being of service.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (19, 'The Individualist', 'Fiercely independent and capable, you learn to balance self-reliance with interdependence.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (20, 'The Harmonizer', 'Deeply sensitive to others'' feelings, you build cooperative, attuned relationships.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (21, 'The Creative Spark', 'A highly charged imagination and social charm make you an inspiring, expressive presence.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (22, 'The Master Builder', 'Vision plus the inner strength to build institutions and realize big ideas.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (23, 'The Versatile', 'Highly adaptable with an easy way with people, you handle change better than most.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (24, 'The Devoted', 'Loyal and warm-hearted, you nurture, protect, and provide, skilled at stable relationships.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (25, 'The Investigator', 'A deep researcher and analyst who never takes things at face value and grows through reflection.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (26, 'The Achiever-Helper', 'Driven to succeed in ways that benefit others, with intuitive insight into what people need.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (27, 'The Tolerant Mind', 'Open, compassionate, and well-informed, you apply broad knowledge toward the greater good.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (28, 'The Team Leader', 'Ambitious and self-assured, you lead by bringing people together toward shared achievement.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (29, 'The Connector', 'An intuitive synthesizer who sees how everything and everyone is connected.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (30, 'The Performer', 'An artist at heart with a gift for creative communication and an uplifting effect on others.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
INSERT INTO num_meaning_birthday (day, title, description) VALUES (31, 'The Foundation', 'A blend of practicality and imagination, you turn creative ideas into organized, real results.') ON CONFLICT (day) DO UPDATE SET title = EXCLUDED.title, description = EXCLUDED.description;
