INSERT INTO num_compatibility_meta (id, is_deterministic, master_reduction_for_lookup, commonly_cited_harmonious_pairs, note) VALUES ('life_path_compatibility', FALSE, '{"11": 2, "22": 4, "33": 6}'::JSONB, '[[1, 5], [2, 6], [4, 8], [3, 9], [3, 5], [1, 3]]'::JSONB, 'Life Path compatibility. INTERPRETIVE, NOT DETERMINISTIC: a ''challenging'' rating does not mean incompatible, and the published matrix is asymmetric (a number''s list does not always mirror the other''s). Master Life Paths are reduced (11->2, 22->4, 33->6) for this lookup. Use as a soft first-pass heuristic only, then layer in the full chart. Source: numerology.com.') ON CONFLICT (id) DO UPDATE SET is_deterministic = EXCLUDED.is_deterministic, master_reduction_for_lookup = EXCLUDED.master_reduction_for_lookup, commonly_cited_harmonious_pairs = EXCLUDED.commonly_cited_harmonious_pairs, note = EXCLUDED.note;
INSERT INTO num_meta (key, value) VALUES ('metadata', '{"name": "Moon Rhythms Deterministic Numerology Reference", "version": "v1", "generated": "2026-06-23", "system": "Pythagorean (default)", "description": "Single source of truth for all deterministic numerology data used by Moon Rhythms. This file is for STRUCTURED LOOKUP and exact computation reproducibility. It encodes the letter values, reduction rules, and formulas the app''s numerology engine (lib/numerology.js) already ships, then EXTENDS them with researched, cross-checked numerology structures (Chaldean alternate, karmic debt/lessons, hidden passion, bridges, personal month/day, essence/transit, full birthday and pinnacle/challenge meaning tables). Interpretive long-form prose belongs in a separate RAG corpus, NOT here. Descriptor strings are concise, modern, grounded, and warm: no mystical/woo language, no fate-talk, no emojis, no em dashes.", "sources_summary": "See numerology_RESEARCH.md for full source list with URLs and access dates (all 2026-06-23). Primary references: worldnumerology.com (Hans Decoz), numerology.com, tokenrock.com, affinitynumerology.com, numerology.center, feliciabender.com, plus Chaldean table cross-checks."}'::JSONB) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO num_meta (key, value) VALUES ('design_decisions', '{"system_default": "Pythagorean. Letter values A=1..I=9, J=1..R=9, S=1..Z=8. This matches the app''s lib/numerology.js LETTER_VALUES map exactly and is what every core number is computed from.", "chaldean_included_as_alternate": "The classical Chaldean (Cheiro) table is included under systems.chaldean as a reference-only alternate. It is NOT what the app computes with. Chaldean values run 1-8; 9 is never assigned to a letter (treated as sacred). If the app ever offers a Chaldean toggle, this table is the source.", "y_rule": "The phonetically correct rule (Y is a vowel when it carries the only vowel sound of a syllable, a consonant otherwise) requires syllable analysis and is documented for reference. The app''s CURRENT engine uses a SIMPLER deterministic convention: vowels = {a,e,i,o,u} only, and Y is ALWAYS treated as a consonant (it is not in the VOWELS set in lib/numerology.js). This file records both: vowel_consonant_rules.app_engine_convention is the reproducible one; vowel_consonant_rules.standard_phonetic_rule and the y_as_vowel guidance document the more accurate convention for any future upgrade. W is always a consonant in both the app and the standard modern-software default.", "master_numbers": "Master numbers are [11, 22, 33]. They are preserved (not reduced) when an intermediate or final sum lands on 11, 22, or 33, for the core numbers and name-derived cycles. The app''s reduceToSingle() implements exactly this (stops reducing when n is in [11,22,33]). 44 is NOT treated as a master number by the canonical Western (Decoz) school; it is a ''Power number''. We expose include_44 as a documented optional flag set false.", "challenges_reduce_masters": "Challenge numbers are the one place master status is NOT preserved: they always reduce to a single digit 0-8 (0 is valid and common). The app''s challenges() uses reduceStrict() for this, matching Decoz.", "karmic_debt_detection": "A karmic debt (13, 14, 16, 19) is detected on the PRE-REDUCTION total of a core number, before it collapses to a single digit. The app does not currently surface karmic debt; this file documents the standard detection rule and themes so the assembler/AI can compute and reference it. Reductions: 13->4, 14->5, 16->7, 19->1.", "pinnacle_timing_convention": "First Pinnacle runs from birth to age (36 - reduced Life Path); each of the second and third Pinnacles lasts 9 years; the fourth runs to end of life. This is the canonical Decoz convention and matches the app''s pinnacles() (firstEnd = 36 - lifePath, then +9 windows). Alternative softened ranges (''27-35'', ''30-35'') from other sources are noted in pinnacles.timing.alternative_conventions.", "life_cycles_timing_deviation": "IMPORTANT: the app''s lifeCycles() reuses the pinnacle ''firstEnd = 36 - lifePath'' boundary for the three Period Cycles (Formative birth..36-LP, Productive next 27 years, Harvest to end). The canonical Decoz Period-Cycle rule is DIFFERENT: cycle 1 ends at the first Personal Year 1 on or after age 27, cycle 2 lasts exactly 27 years, cycle 3 to death. We encode the app''s actual behavior under life_cycles.app_engine_timing (reproducible) AND the Decoz canonical rule under life_cycles.canonical_decoz_timing (documented). Pinnacles and Period Cycles do NOT share a transition age in the canonical system; the app conflates them. Flagged here, app code not changed.", "personal_year_master_handling": "The app reduces the Personal Year fully to a single digit (reduceToSingle on the final sum, with month/day/year components reduced via reduceStrict first). Some schools keep 11/22 if the Personal Year total is a master number. We follow the app (single digit 1-9 for Personal Year output) and note the alternative.", "extended_vs_app": "Extracted-from-app (exact, reproducible): Pythagorean letter values, vowel set, reduction rules, Life Path / Expression / Soul Urge / Personality / Birthday / Maturity / Personal Year formulas, 4 Pinnacles (+ 36-LP timing), 4 Challenges, 3 Life Cycles, and the meaning tables the app shipped for Life Path 1-33, Expression, Soul Urge, Personality, Personal Year. Added-from-research (cross-checked >=2 reputable sources, see numerology_RESEARCH.md): Chaldean table, vowel/consonant + Y rule documentation, karmic debt, karmic lessons, hidden passion/intensity, bridge numbers, personal month/day, essence/transit method, full Birthday 1-31 meanings, Pinnacle/Challenge meaning tables, Maturity meanings, core single-digit + master meanings, and an interpretive Life Path compatibility matrix (flagged non-deterministic).", "voice": "All descriptor strings are short, grounded, and warm. No ''cosmic'', ''destined'', ''written in the stars'', no emojis, no em dashes. Where a classical source used loaded or fatalistic language it was neutralized. Karmic / past-life framing from classical sources is reframed as present-tense growth themes (e.g. ''a lesson to develop X'' rather than ''debt from a past life'')."}'::JSONB) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;
